package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that error messages for offset-related fields use user-friendly names
 * instead of internal field names.
 */
class OffsetFieldNamesTest {

    @Test
    fun testOffsetHoursErrorMessage() {
        val format = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            char(' ')
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        // Try to format without setting the offset - should get a user-friendly error message
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                setDateTime(LocalDateTime(2020, 3, 16, 23, 59, 59))
                // Note: offset is NOT set intentionally to trigger the error
            }
        }

        val message = exception.message ?: fail("Exception should have a message")
        // The error message should mention "offsetHours", not "totalHoursAbs"
        assertContains(message, "offsetHours", "Error message should contain user-friendly field name 'offsetHours'")
        assertFalse(message.contains("totalHoursAbs"), "Error message should NOT contain internal field name 'totalHoursAbs'")
    }

    @Test
    fun testOffsetMinutesOfHourErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetMinutesOfHour()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Note: offset is NOT set intentionally to trigger the error
            }
        }

        val message = exception.message ?: fail("Exception should have a message")
        // The error message should mention "offsetMinutesOfHour", not "minutesOfHour"
        assertContains(message, "offsetMinutesOfHour", "Error message should contain user-friendly field name 'offsetMinutesOfHour'")
        assertFalse(message.contains("minutesOfHour") && !message.contains("offsetMinutesOfHour"), 
            "Error message should NOT contain internal field name 'minutesOfHour' without prefix")
    }

    @Test
    fun testOffsetSecondsOfMinuteErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetSecondsOfMinute()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Note: offset is NOT set intentionally to trigger the error
            }
        }

        val message = exception.message ?: fail("Exception should have a message")
        // The error message should mention "offsetSecondsOfMinute", not "secondsOfMinute"
        assertContains(message, "offsetSecondsOfMinute", "Error message should contain user-friendly field name 'offsetSecondsOfMinute'")
        assertFalse(message.contains("secondsOfMinute") && !message.contains("offsetSecondsOfMinute"), 
            "Error message should NOT contain internal field name 'secondsOfMinute' without prefix")
    }

    @Test
    fun testFormatWorksWhenOffsetIsSet() {
        val format = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            char(' ')
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            optional {
                char(':')
                offsetSecondsOfMinute()
            }
        }

        // Format with offset properly set - should succeed
        val result = format.format {
            setDateTime(LocalDateTime(2020, 3, 16, 23, 59, 59))
            setOffset(UtcOffset(hours = 3))
        }

        assertEquals("2020-03-16 23:59:59 +03:00", result)
    }
}
"}

